#include<cstdio>
#include<cstring>
#define rep(a,b,c) for(int c(a);c<=(b);++c)
#define drep(a,b,c) for(int c(a);c>=(b);--c)
const int Mod=1e9+1;int n,dp[1<<12],g[1<<12],ans=1;
inline void DN(int &x){x>=Mod?x-=Mod:0;} inline void UP(int &x){x<0?x+=Mod:0;}
inline void FMT(int *a,int n)
{
	for(int i=0;i<n;++i)
	{
		for(int S=1;S<(1<<n);++S)if(S>>i&1)
		{
			DN(a[S]+=a[S^(1<<i)]);
		}
	}
}
int p3[25],p2[25];bool lk[1<<12];
inline int work(int k)
{
	int m=1;for(;p3[m]*k<=n;++m);
	for(int S=0;S<(1<<m);++S){dp[S]=lk[S];}
	for(int x=1;p2[x]*k<=n;++x)
	{
		int nm=1;for(;p2[x]*p3[nm]*k<=n;++nm);
		int nAll=(1<<nm)-1;
		for(int S=(1<<nm);S<(1<<m);++S)DN(dp[S&nAll]+=dp[S]);
		m=nm;memcpy(g,dp,sizeof(int)<<nm);FMT(g,nm);
		for(int S=0;S<(1<<m);++S)if(lk[S])dp[S]=g[S^nAll];
//		printf("%d(%d) :: ",x,m);
//		for(int S=0;S<(1<<m);++S)printf("%d ",dp[S]);puts("");
		
	}
	int ans=0;for(int S=0;S<(1<<m);++S)DN(ans+=dp[S]);return ans;
}
int main()
{
	scanf("%d",&n);p3[0]=p2[0]=1;
	for(int S=0;S<(1<<12);++S)
	{
		bool flag=0;for(int i=0;i<n-1;++i)if((S>>i&3)==3){flag=true;break;}
		lk[S]=!flag;
	}
	for(int i=1;;++i){p3[i]=p3[i-1]*3;if(p3[i]>n)break;}
	for(int i=1;;++i){p2[i]=p2[i-1]*2;if(p2[i]>n)break;}
//	rep(1,n,i)if(i%2!=0&&i%3!=0)printf("work(%d) :: %d\n",i,work(i));
	rep(1,n,i)if(i%2!=0&&i%3!=0)ans=1ll*ans*work(i)%Mod;
	printf("%d\n",ans);
}
